// ValidateTunnelledMcpServerResponseBody runs the validations defined on
// TunnelledMcpServerResponseBody
func ValidateTunnelledMcpServerResponseBody(body *TunnelledMcpServerResponseBody) (err error) {
	if body.ID == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("id", "body"))
	}
	if body.ProjectID == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("project_id", "body"))
	}
	if body.Name == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("name", "body"))
	}
	if body.KeyPrefix == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("key_prefix", "body"))
	}
	if body.Status == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("status", "body"))
	}
	if body.ConnectionStatus == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("connection_status", "body"))
	}
	if body.Connections == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("connections", "body"))
	}
	if body.ActiveConnectionCount == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("active_connection_count", "body"))
	}
	if body.ActiveConsumerSessionCount == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("active_consumer_session_count", "body"))
	}
	if body.CreatedAt == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("created_at", "body"))
	}
	if body.UpdatedAt == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("updated_at", "body"))
	}
	if body.ID != nil {
		err = goa.MergeErrors(err, goa.ValidateFormat("body.id", *body.ID, goa.FormatUUID))
	}
	if body.ProjectID != nil {
		err = goa.MergeErrors(err, goa.ValidateFormat("body.project_id", *body.ProjectID, goa.FormatUUID))
	}
	if body.Status != nil {
		if !(*body.Status == "created" || *body.Status == "active" || *body.Status == "revoked") {
			err = goa.MergeErrors(err, goa.InvalidEnumValueError("body.status", *body.Status, []any{"created", "active", "revoked"}))
		}
	}
	if body.ConnectionStatus != nil {
		if !(*body.ConnectionStatus == "connected" || *body.ConnectionStatus == "inactive" || *body.ConnectionStatus == "never_connected") {
			err = goa.MergeErrors(err, goa.InvalidEnumValueError("body.connection_status", *body.ConnectionStatus, []any{"connected", "inactive", "never_connected"}))
		}
	}
	if body.LastSeenAt != nil {
		err = goa.MergeErrors(err, goa.ValidateFormat("body.last_seen_at", *body.LastSeenAt, goa.FormatDateTime))
	}
	for _, e := range body.Connections {
		if e != nil {
			if err2 := ValidateTunnelledMcpConnectionResponseBody(e); err2 != nil {
				err = goa.MergeErrors(err, err2)
			}
		}
	}
	if body.CreatedAt != nil {
		err = goa.MergeErrors(err, goa.ValidateFormat("body.created_at", *body.CreatedAt, goa.FormatDateTime))
	}
	if body.UpdatedAt != nil {
		err = goa.MergeErrors(err, goa.ValidateFormat("body.updated_at", *body.UpdatedAt, goa.FormatDateTime))
	}
	return
}

